CREATE OR REPLACE FUNCTION OFSERM.DEFAULT_FUND_CONTRIBUTION_DATA_POPULATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FCT_CCP_DETAILS(N_MIS_DATE_SKEY,N_GAAP_SKEY,F_CCP_HYPOTHETICAL_CAPITL_CALC,F_QUALIFIED_CCP_FLAG,N_CCP_HYPOTHETICAL_CAPITAL,N_CCP_OWN_DFC_AMT,N_CENTRAL_COUNTERPARTY_SKEY,N_CM_TOT_FUN_DFC_AMT,N_CM_TOT_UNFUN_DFC_AMT,N_ENTITY_FUNDED_DFC_AMOUNT,N_ENTITY_INITIAL_MARGIN,N_ENTITY_UNFUNDED_DFC_AMOUNT,N_EXCHANGE_RATE,N_MAX_NET_POTENTIAL_EXP,N_RUN_PARAMETER_SETUP_SKEY,N_RUN_SKEY,N_SECOND_MAX_NET_POTNL_EXP,N_TOTAL_INITIAL_MARGIN,N_TOTAL_NET_POTENTIAL_EXP,N_ENTITY_SKEY,N_CCP_HYPOTHETICAL_CAPITAL_NCY,N_CCP_OWN_DFC_AMT_NCY,N_CM_TOT_FUN_DFC_AMT_NCY,N_CM_TOT_UNFUN_DFC_AMT_NCY,N_MAX_NET_POTENTIAL_EXP_NCY,N_NO_OF_CLEARING_MEMBER,N_SECOND_MAX_NET_POTNL_EXP_NCY,N_TOTAL_EAD_CM,N_TOTAL_INITIAL_MARGIN_NCY,N_TOTAL_NET_POTENTIAL_EXP_NCY,V_CCY_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),DIM_PARTY_CCP.F_CCP_HYPOTHETICAL_CAPITL_CALC,DIM_PARTY_CCP.F_QUALIFIED_CCP_FLAG,STG_CCP_DETAILS.n_ccp_hypothetical_capital*FSI_CAP_CURRENCY_CONVERSION.n_exchange_rate,STG_CCP_DETAILS.n_ccp_own_dfc_amt*FSI_CAP_CURRENCY_CONVERSION.n_exchange_rate,DIM_PARTY_CCP.N_PARTY_SKEY,STG_CCP_DETAILS.n_cm_tot_fun_dfc_amt*FSI_CAP_CURRENCY_CONVERSION.n_exchange_rate,STG_CCP_DETAILS.n_cm_tot_unfun_dfc_amt*FSI_CAP_CURRENCY_CONVERSION.n_exchange_rate,SUM(CASE WHEN COALESCE(DIM_BASEL_PRODUCT_TYPE.F_UNFUNDED_IND,'N') = 'N' AND FSI_PLACED_COLLATERAL.V_MARGIN_TYPE = 'DF' THEN FSI_PLACED_COLLATERAL.N_COLLATERAL_FAIR_VALUE ELSE 0 END),SUM(CASE WHEN FSI_PLACED_COLLATERAL.V_MARGIN_TYPE = 'IM' THEN FSI_PLACED_COLLATERAL.N_COLLATERAL_FAIR_VALUE ELSE 0 END),SUM(CASE WHEN COALESCE(DIM_BASEL_PRODUCT_TYPE.F_UNFUNDED_IND,'N') = 'Y' AND FSI_PLACED_COLLATERAL.V_MARGIN_TYPE = 'DF' THEN FSI_PLACED_COLLATERAL.N_COLLATERAL_FAIR_VALUE ELSE 0 END),FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_CCP_DETAILS.N_MAX_NET_POTENTIAL_EXP*FSI_CAP_CURRENCY_CONVERSION.n_exchange_rate,max(run_parameters.N_RUN_PARAMETER_SETUP_SKEY),'870',STG_CCP_DETAILS.N_SECOND_MAX_NET_POTNL_EXP*FSI_CAP_CURRENCY_CONVERSION.n_exchange_rate,STG_CCP_DETAILS.N_TOTAL_INITIAL_MARGIN*FSI_CAP_CURRENCY_CONVERSION.n_exchange_rate,STG_CCP_DETAILS.n_total_net_potential_exp*FSI_CAP_CURRENCY_CONVERSION.n_exchange_rate,to_char(FSI_PLACED_COLLATERAL.N_ENTITY_SKEY),to_char(STG_CCP_DETAILS.N_CCP_HYPOTHETICAL_CAPITAL),to_char(STG_CCP_DETAILS.N_CCP_OWN_DFC_AMT),to_char(STG_CCP_DETAILS.N_CM_TOT_FUN_DFC_AMT),to_char(STG_CCP_DETAILS.N_CM_TOT_UNFUN_DFC_AMT),to_char(STG_CCP_DETAILS.N_MAX_NET_POTENTIAL_EXP),to_char(STG_CCP_DETAILS.N_NO_OF_CLEARING_MEMBER),to_char(STG_CCP_DETAILS.N_SECOND_MAX_NET_POTNL_EXP),to_char(STG_CCP_DETAILS.N_TOTAL_EAD_CM),to_char(STG_CCP_DETAILS.N_TOTAL_INITIAL_MARGIN),to_char(STG_CCP_DETAILS.N_TOTAL_NET_POTENTIAL_EXP),STG_CCP_DETAILS.V_CCY_CODE FROM STG_CCP_DETAILS LEFT OUTER JOIN DIM_DATES ON STG_CCP_DETAILS.FIC_MIS_DATE = DIM_DATES.D_CALENDAR_DATE LEFT OUTER JOIN DIM_GAAP ON STG_CCP_DETAILS.V_GAAP_CODE = DIM_GAAP.V_GAAP_CODE AND DIM_DATES.D_CALENDAR_DATE BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.D_RECORD_END_DATE LEFT OUTER JOIN DIM_PARTY DIM_PARTY_CCP ON STG_CCP_DETAILS.V_CENTRAL_COUNTERPARTY_CODE = DIM_PARTY_CCP.V_PARTY_ID AND STG_CCP_DETAILS.FIC_MIS_DATE BETWEEN DIM_PARTY_CCP.D_RECORD_START_DATE AND DIM_PARTY_CCP.D_RECORD_END_DATE LEFT OUTER JOIN FSI_PLACED_COLLATERAL ON FSI_PLACED_COLLATERAL.N_RUN_SKEY = '870' AND FSI_PLACED_COLLATERAL.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PLACED_COLLATERAL.N_CENTRAL_COUNTERPARTY_SKEY = DIM_PARTY_CCP.N_PARTY_SKEY INNER JOIN ( FCT_ENTITY_INFO LEFT OUTER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_APPR_SKEY ) ON FSI_PLACED_COLLATERAL.N_ENTITY_SKEY = FCT_ENTITY_INFO.N_ENTITY_SKEY AND FCT_ENTITY_INFO.N_GAAP_SKEY = DIM_GAAP.N_GAAP_SKEY LEFT OUTER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = FCT_ENTITY_INFO.N_RUN_SKEY LEFT OUTER JOIN dim_basel_product_type ON dim_basel_product_type.n_basel_prod_type_skey = fsi_placed_collateral.n_basel_prod_type_skey LEFT OUTER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_DATES.n_date_skey = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY LEFT OUTER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' LEFT OUTER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND RUN_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_CCP_DETAILS.V_CCY_CODE WHERE 1=1 AND STG_CCP_DETAILS.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND COALESCE(FCT_ENTITY_INFO.F_CAP_CONSL_ENTITY_IND, 'N') = 'Y' AND DIM_BASEL_CAP_CONSL_APPR.V_BASEL_CAP_CONSL_APPR_CODE IN ( 'FLCS' ,'PRCS' ) AND FCT_ENTITY_INFO.N_RUN_SKEY = '870' AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') GROUP BY dim_dates.n_date_skey ,dim_gaap.n_gaap_skey ,fsi_placed_collateral.n_entity_skey ,stg_ccp_details.n_ccp_hypothetical_capital ,stg_ccp_details.n_ccp_own_dfc_amt ,stg_ccp_details.n_cm_tot_fun_dfc_amt ,stg_ccp_details.n_cm_tot_unfun_dfc_amt ,stg_ccp_details.n_max_net_potential_exp ,stg_ccp_details.n_no_of_clearing_member ,stg_ccp_details.n_second_max_net_potnl_exp ,stg_ccp_details.n_total_initial_margin ,stg_ccp_details.n_total_ead_cm ,stg_ccp_details.n_total_net_potential_exp ,stg_ccp_details.v_ccy_code ,dim_party_ccp.f_qualified_ccp_flag ,dim_party_ccp.n_party_skey ,stg_ccp_details.fic_mis_date ,FSI_CAP_RUN_EXE_PARAMETERS.n_entity_skey ,DIM_PARTY_CCP.F_CCP_HYPOTHETICAL_CAPITL_CALC ,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE LOG ERRORS INTO FCT_CCP_DETAILS$ ('1776770006653_6876681_20260331_1_Job_2ae6585e898941058cf375c4e7f6e9eb') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
